import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.Files;
import java.util.Scanner;

public class PathTraversalSecure {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter file name: ");
        String fileName = scanner.next();

        Path basePath = Paths.get("/path/to/directory/"); // Base directory

        try {
            Path filePath = basePath.resolve(fileName).normalize(); // Resolves against base path and normalizes
            if(filePath.startsWith(basePath) && Files.exists(filePath)) { // Check if resolved path is within base directory and exists
                System.out.println("File exists!");
            } else {
                System.out.println("File does not exist.");
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

